package com.example.orders.controller;

import com.example.orders.dto.OrderResponse;
import com.example.orders.entity.Order;
import com.example.orders.exception.ForbiddenException;
import com.example.orders.exception.OrderNotFoundException;
import com.example.orders.repository.OrderRepository;
import com.example.orders.security.UserPrincipal;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/orders")
public class OrderController {

    private final OrderRepository orderRepository;

    public OrderController(OrderRepository orderRepository) {
        this.orderRepository = orderRepository;
    }

    @GetMapping("/{orderId}")
    public ResponseEntity<OrderResponse> getOrderById(
            @PathVariable Long orderId,
            @AuthenticationPrincipal UserPrincipal currentUser) {

        Order order = orderRepository.findById(orderId)
                .orElseThrow(() -> new OrderNotFoundException("Order not found with id: " + orderId));

        // Object-level authorization: ensure the authenticated user owns this order
        // or has an ADMIN role. This prevents IDOR (Insecure Direct Object Reference).
        if (!isAuthorizedToAccess(currentUser, order)) {
            throw new ForbiddenException("You are not authorized to access this order.");
        }

        // Return a DTO with an allowlist of fields — never expose internal/privileged
        // fields such as internal notes, cost price, profit margin, etc.
        OrderResponse response = toSafeResponse(order);

        return ResponseEntity.ok(response);
    }

    private boolean isAuthorizedToAccess(UserPrincipal currentUser, Order order) {
        // Tenant scoping: the order must belong to the same tenant as the user
        if (!currentUser.getTenantId().equals(order.getTenantId())) {
            return false;
        }

        // Admins within the same tenant can access any order
        if (currentUser.getRoles().contains("ROLE_ADMIN")) {
            return true;
        }

        // Regular users can only access their own orders
        return currentUser.getUserId().equals(order.getUserId());
    }

    private OrderResponse toSafeResponse(Order order) {
        // Field allowlist: only expose safe, non-privileged fields
        return new OrderResponse(
                order.getId(),
                order.getOrderNumber(),
                order.getStatus(),
                order.getItems(),
                order.getTotalAmount(),
                order.getCurrency(),
                order.getCreatedAt(),
                order.getUpdatedAt()
        );
    }
}